class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        best = 1
        for i in range(n):
            pairs = 0
            length = 1
            for j in range(i, n):
                if j > i:
                    if s[j] == s[j - 1]:
                        pairs += 1
                    if pairs > 1:
                        break
                    length = j - i + 1
                best = max(best, length)
        return best

