class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        left = 0
        prev_pair_pos = -1
        best = 1
        for right in range(1, n):
            if s[right] == s[right - 1]:
                if prev_pair_pos >= left:
                    left = prev_pair_pos + 1
                prev_pair_pos = right - 1
            best = max(best, right - left + 1)
        return best

