var longestSemiRepetitiveSubstring = function(s) {
    const n = s.length;
    let left = 0, prevPairPos = -1, best = 1;
    for (let right = 1; right < n; right++) {
        if (s[right] === s[right - 1]) {
            if (prevPairPos >= left) {
                left = prevPairPos + 1;
            }
            prevPairPos = right - 1;
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
